import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const generateBio = async (tone: 'artistic' | 'minimalist' | 'professional') => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Generate a short, ${tone} biography for "Sophie Liner", a multidisciplinary artist focused on minimalist aesthetics, video, and architectural beauty. Keep it under 40 words.`,
      config: {
        temperature: 0.7,
        topP: 0.95,
      },
    });
    return response.text;
  } catch (error) {
    console.error("Error generating bio:", error);
    return "Sophie Liner is a multidisciplinary artist based in London, exploring the intersection of light, space, and motion through digital and physical mediums.";
  }
};

