import React, { useState } from 'react';

const Contact: React.FC = () => {
  const [formState, setFormState] = useState({ name: '', email: '', message: '' });
  const [submitted, setSubmitted] = useState(false);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    // In a real app, send data to backend
    setSubmitted(true);
  };

  if (submitted) {
    return (
      <div className="h-64 flex flex-col justify-center animate-in zoom-in duration-500">
        <h2 className="text-3xl font-light tracking-tight mb-4">Thank you.</h2>
        <p className="text-gray-400 font-light">Your message has been sent to Sophie.</p>
        <button 
          onClick={() => setSubmitted(false)}
          className="mt-8 text-xs uppercase tracking-widest text-black border-b border-black w-max pb-1"
        >
          Send another
        </button>
      </div>
    );
  }

  return (
    <div className="space-y-12 animate-in fade-in slide-in-from-bottom-4 duration-700">
      <h2 className="text-3xl font-light tracking-tight">Contact</h2>

      <div className="max-w-md">
        <form onSubmit={handleSubmit} className="space-y-8">
          <div className="space-y-1">
            <label htmlFor="name" className="text-[10px] uppercase tracking-[0.2em] text-gray-400">Name</label>
            <input
              required
              id="name"
              type="text"
              value={formState.name}
              onChange={(e) => setFormState({...formState, name: e.target.value})}
              className="w-full bg-transparent border-b border-gray-100 py-2 focus:border-black transition-colors outline-none font-light"
            />
          </div>
          <div className="space-y-1">
            <label htmlFor="email" className="text-[10px] uppercase tracking-[0.2em] text-gray-400">Email</label>
            <input
              required
              id="email"
              type="email"
              value={formState.email}
              onChange={(e) => setFormState({...formState, email: e.target.value})}
              className="w-full bg-transparent border-b border-gray-100 py-2 focus:border-black transition-colors outline-none font-light"
            />
          </div>
          <div className="space-y-1">
            <label htmlFor="message" className="text-[10px] uppercase tracking-[0.2em] text-gray-400">Message</label>
            <textarea
              required
              id="message"
              rows={4}
              value={formState.message}
              onChange={(e) => setFormState({...formState, message: e.target.value})}
              className="w-full bg-transparent border-b border-gray-100 py-2 focus:border-black transition-colors outline-none font-light resize-none"
            ></textarea>
          </div>

          <button 
            type="submit"
            className="group flex items-center space-x-2 text-sm uppercase tracking-widest font-medium pt-4"
          >
            <span>Send Message</span>
            <span className="group-hover:translate-x-1 transition-transform">→</span>
          </button>
        </form>

        <div className="mt-24 pt-12 border-t border-gray-50 flex flex-col space-y-4">
          <div className="text-xs font-light text-gray-400">
            Socials
          </div>
          <div className="flex space-x-6 text-sm">
