      </div>
    );
  }

  return (
    <div className="space-y-12 animate-in fade-in slide-in-from-bottom-4 duration-700">
      <h2 className="text-3xl font-light tracking-tight text-[#555555]">Contact</h2>

      <div className="max-w-md">
        <form onSubmit={handleSubmit} className="space-y-8">
          <div className="space-y-1">
            <label htmlFor="name" className="text-[10px] uppercase tracking-[0.2em] text-gray-400">Name</label>
            <input
              required
              id="name"
              type="text"
              value={formState.name}
              onChange={(e) => setFormState({...formState, name: e.target.value})}
              className="w-full bg-transparent border-b border-gray-100 py-2 focus:border-[#555555] transition-colors outline-none font-light text-[#555555]"
            />
          </div>
          <div className="space-y-1">
            <label htmlFor="email" className="text-[10px] uppercase tracking-[0.2em] text-gray-400">Email</label>
            <input
              required
              id="email"
              type="email"
              value={formState.email}
              onChange={(e) => setFormState({...formState, email: e.target.value})}
              className="w-full bg-transparent border-b border-gray-100 py-2 focus:border-[#555555] transition-colors outline-none font-light text-[#555555]"
            />
          </div>
          <div className="space-y-1">
            <label htmlFor="message" className="text-[10px] uppercase tracking-[0.2em] text-gray-400">Message</label>
            <textarea
              required
              id="message"
              rows={4}
              value={formState.message}
              onChange={(e) => setFormState({...formState, message: e.target.value})}
              className="w-full bg-transparent border-b border-gray-100 py-2 focus:border-[#555555] transition-colors outline-none font-light resize-none text-[#555555]"
            ></textarea>
          </div>

          <button 
            type="submit"
            className="group flex items-center space-x-2 text-sm uppercase tracking-widest font-medium pt-4 text-[#555555]"
          >
            <span>Send Message</span>
            <span className="group-hover:translate-x-1 transition-transform">→</span>
          </button>
        </form>

        <div className="mt-24 pt-12 border-t border-gray-50 flex flex-col space-y-4">
          <div className="text-xs font-light text-gray-400">
            Socials
          </div>
          <div className="flex space-x-6 text-sm text-gray-500">
            <a href="#" className="hover:text-[#555555] transition-colors">Instagram</a>
            <a href="#" className="hover:text-[#555555] transition-colors">Vimeo</a>
